sys_script.script:
(function executeRule(current, previous) {

    // 摒弃容易引发隐式类型转换的 .toString()，强制采用安全的 .getValue() 获取底层真实字符串数值
    var fromState = previous.getValue('state') || '';
    var toState = current.getValue('state') || '';

    // 如果状态没变，直接返回
    if (fromState === toState) return;

    // 如果旧状态为空（新建后首次update），允许通过
    if (!fromState || fromState === '') return;

    // 字典映射关系: 1(下書き), 10(提出済み), 11(担当者決定), 2(配送中), 4(完了), 5(キャンセル), 6(保留中)
    var allowedTransitions = {
        '1':  ['10', '5'],
        '10': ['1', '11', '5'],
        '11': ['10', '2', '5', '6'],
        '2':  ['4', '5', '6'],
        '4':  [], 
        '5':  [], 
        '6':  ['11', '2', '5']
    };

    var allowed = allowedTransitions[fromState] || [];
    var isAllowed = (allowed.indexOf(toState) !== -1);

    if (!isAllowed) {
        // 植入探针：强制输出错误日志至系统日志，捕获拦截现场的真实变量
        gs.error('[Kokoro State Audit] 拦截阻断! 尝试越级流转: fromState=[' + fromState + '] -> toState=[' + toState + '], 记录: ' + current.getUniqueValue());

        current.state = previous.getValue('state'); // 回滚状态
        current.setAbortAction(true);
        return;
    }

    // 4. 记录到 Process Event 表 (日志)
    try {
        var pe = new GlideRecord('x_1821654_kokoro_0_process_event');
        pe.initialize();
        pe.setValue('case_id', current.getUniqueValue());
        pe.setValue('activity', 'State Change: ' + fromState + ' -> ' + toState);
        pe.setValue('user', gs.getUserID());
        pe.insert();
    } catch (e) {
        gs.warn('[Kokoro] Process event logging failed: ' + e.message);
    }

    // 5. 更新当前记录的审计字段
    if (current.isValidField('state_changed_on')) {
        current.setValue('state_changed_on', new GlideDateTime());
    }
    if (current.isValidField('state_changed_by')) {
        current.setValue('state_changed_by', gs.getUserID());
    }

})(current, previous);
